export const theme = {
  colors: {
    background: '#0a0a0a', // Dark Charcoal
    surface: '#141414',
    emerald: '#10b981', // Emerald
    text: {
      primary: '#ffffff',
      muted: 'rgba(255, 255, 255, 0.4)'
    }
  },
  spacing: {
    cardPadding: '2rem',
    inputMargin: '1.5rem'
  }
};
